import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Button,
  FormActions,
  FormRowCol,
  FormSkeleton,
  Input,
  LabelMoney,
  MoneyInput,
  SearchInput,
  Select,
  dispatchAppToast,
  localInputToISOWithOffset,
} from '@linm-soft-org/linm-web-common-components';
import type { ActiveCompanyItem } from '@linm-soft-org/linm-web-common-components';
import { fpcService } from '../../../services/fpc/service';
import { useAppDispatch } from '../../../store/hooks';
import { createCompanySearchConfig } from '../../../components/search/companySearchConfig';
import { createStaticLookupSearchConfig } from '../../../components/search/createStaticLookupSearchConfig';
import type { CostCodeDto, CostPlanItemDto, PlanVoucherDraftDto } from '../../../services/fpc/types';
import styles from './PlanVoucherPage.module.css';

const TEST_ID = 'plan-voucher';

/* ── Format helpers ──────────────────────── */
const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(v);

const fCompact = (v: number): string => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000_000) return `${(abs / 1_000_000_000).toFixed(1)} tỷ`;
  if (abs >= 1_000_000) return `${(abs / 1_000_000).toFixed(0)} triệu`;
  if (abs >= 1_000) return `${(abs / 1_000).toFixed(0)} nghìn`;
  return `${abs.toLocaleString('vi-VN')}`;
};

const todayDateStr = () => {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

/* ── Types ────────────────────────────────── */
type PlanTab = 'revenue' | 'expense';
type GroupMode = 'item' | 'branch';

interface PlanLine {
  id: string;
  entityCode: string;
  entityName: string;
  entityGroup: string;
  plannedAmount: number;
  actualAmount: number;
  mustPay: number;
  debt: number;
  priority: string;
}

interface GroupTotal {
  group: string;
  items: PlanLine[];
  totalPlanned: number;
  totalActual: number;
  totalMustPay: number;
  totalDebt: number;
}

/* ── Status logic ─────────────────────────── */
interface StatusInfo { label: string; bg: string; color: string; }

function getStatusInfo(planned: number, actual: number): StatusInfo {
  if (planned === 0 && actual === 0) return { label: 'Chưa có', bg: '#f1f5f9', color: '#999' };
  if (planned === 0) return { label: 'Chưa lập KH', bg: '#fef3c7', color: '#92400e' };
  const pct = ((actual - planned) / planned) * 100;
  if (Math.abs(pct) <= 10) return { label: 'Đạt', bg: '#d1fae5', color: '#065f46' };
  if (pct < -10) return { label: 'Thấp hơn', bg: '#fef3c7', color: '#92400e' };
  return { label: 'Cao hơn', bg: '#fee2e2', color: '#991b1b' };
}

function getPriorityColor(priority: string): string {
  switch (priority) {
    case 'Critical': return '#991b1b';
    case 'High': return '#d97706';
    case 'Medium': return '#2563eb';
    case 'Low': return '#6b7280';
    default: return '#6b7280';
  }
}

function getPriorityBg(priority: string): string {
  switch (priority) {
    case 'Critical': return '#fee2e2';
    case 'High': return '#fef3c7';
    case 'Medium': return '#dbeafe';
    case 'Low': return '#f3f4f6';
    default: return '#f3f4f6';
  }
}

/* ── Component ────────────────────────────── */
const PlanVoucherPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const isCreate = !id || id === 'new';

  /* ── Period state ──────────────────────── */
  const now = new Date();
  const [planYear, setPlanYear] = useState(now.getFullYear());
  const [planMonth, setPlanMonth] = useState(now.getMonth() + 1);

  /* ── Voucher entity ────────────────────── */
  const [voucher, setVoucher] = useState<PlanVoucherDraftDto | null>(null);
  const [voucherLoading, setVoucherLoading] = useState(!isCreate);

  /* ── Data state ────────────────────────── */
  const [costCodes, setCostCodes] = useState<CostCodeDto[]>([]);
  const [costPlans, setCostPlans] = useState<CostPlanItemDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadedPeriod, setLoadedPeriod] = useState({ year: 0, month: 0 });

  /* ── UI state ──────────────────────────── */
  const [activeTab, setActiveTab] = useState<PlanTab>('expense');
  const [groupMode, setGroupMode] = useState<GroupMode>('item');
  const [editMode, setEditMode] = useState(isCreate);
  const [saving, setSaving] = useState(false);
  const [editedLines, setEditedLines] = useState<Record<string, number>>({});
  const [editedMustPay, setEditedMustPay] = useState<Record<string, number>>({});
  const [editedNotes, setEditedNotes] = useState<Record<string, string>>({});
  const [selectedLineIndex, setSelectedLineIndex] = useState(-1);

  /* ── Local add/delete state ────────────── */
  const [localAddedLines, setLocalAddedLines] = useState<PlanLine[]>([]);
  const [localDeletedIds, setLocalDeletedIds] = useState<Set<string>>(new Set());
  const localIdCounter = useRef(0);

  /* ── Voucher header state ──────────────── */
  const [voucherCode, setVoucherCode] = useState(isCreate
    ? `PKH-${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}-0001`
    : '');
  const [voucherDate, setVoucherDate] = useState(todayDateStr());
  const [description, setDescription] = useState('');

  /* ── Branch filter state ───────────────── */
  const [branchCode, setBranchCode] = useState('');
  const [selectedCompany, setSelectedCompany] = useState<ActiveCompanyItem | null>(null);

  /* ── Header compact state ──────────────── */
  const [headerExpanded, setHeaderExpanded] = useState(true);

  /* ── Load voucher (edit mode) ──────────── */
  useEffect(() => {
    if (!isCreate && id && id !== 'new') {
      setVoucherLoading(true);
      fpcService.getPlanVoucherById(id)
        .then(v => {
          setVoucher(v);
          setVoucherCode(v.code);
          setVoucherDate(v.voucherDate.substring(0, 10));
          setPlanYear(v.planYear);
          setPlanMonth(v.planMonth);
          setDescription(v.description || '');
          setBranchCode(v.branchCode);
        })
        .catch(() => {
          dispatchAppToast(dispatch, { message: 'Không tìm thấy phiếu kế hoạch', type: 'error' });
        })
        .finally(() => setVoucherLoading(false));
    }
  }, [id, isCreate, dispatch]);

  /* ── Search configs ────────────────────── */
  const companySearchConfig = useMemo(() => createCompanySearchConfig(), []);

  const costCodeSearchConfig = useMemo(() => createStaticLookupSearchConfig({
    loadItems: () => costCodes,
    getKey: item => item.id,
    getCode: item => item.code,
    getName: item => item.name,
    getFilterText: item => `${item.code} ${item.name} ${item.groupName ?? ''}`,
    codeHeaderLabel: 'Mã CP',
    nameHeaderLabel: 'Tên khoản mục',
  }), [costCodes]);

  /* ── Fetch data ────────────────────────── */
  const fetchData = useCallback(async (year: number, month: number, branch?: string) => {
    setLoading(true);
    try {
      const [codes, plans] = await Promise.all([
        fpcService.getCostCodeList(),
        fpcService.getCostPlanList({ year, month, branchCode: branch || undefined }),
      ]);
      setCostCodes(codes.filter(c => c.isActive));
      setCostPlans(plans);
      setLoadedPeriod({ year, month });
    } catch {
      dispatchAppToast(dispatch, { message: 'Không thể tải dữ liệu kế hoạch', type: 'error' });
    } finally {
      setLoading(false);
    }
  }, [dispatch]);

  useEffect(() => {
    fetchData(planYear, planMonth, branchCode);
  }, [fetchData, planYear, planMonth, branchCode]);

  /* ── Period change ─────────────────────── */
  const handlePeriodChange = (year: number, month: number) => {
    setPlanYear(year);
    setPlanMonth(month);
    setEditMode(false);
    setEditedLines({});
    setEditedMustPay({});
    setEditedNotes({});
    setLocalAddedLines([]);
    setLocalDeletedIds(new Set());
    setVoucherCode(`KH-${year}${String(month).padStart(2, '0')}-001`);
    setDescription(`Kế hoạch tài chính tháng ${month}/${year}`);
  };

  /* ── Branch change ─────────────────────── */
  const handleBranchChange = (item: ActiveCompanyItem | null) => {
    const code = item?.code ?? item?.id ?? '';
    setBranchCode(code);
    setSelectedCompany(item);
    setEditMode(false);
    setEditedLines({});
    setEditedMustPay({});
    setEditedNotes({});
    setLocalAddedLines([]);
    setLocalDeletedIds(new Set());
  };

  /* ── Revenue lines ─────────────────────── */
  const revenueLines = useMemo((): PlanLine[] => {
    const incomeCodes = new Set(costCodes.filter(c => c.costType === 'Income').map(c => c.code));
    return costPlans
      .filter(p => incomeCodes.has(p.costCode))
      .map(p => ({
        id: p.id,
        entityCode: p.costCode,
        entityName: p.costCodeName || p.costCode,
        entityGroup: p.groupName || 'Khác',
        plannedAmount: p.plannedAmount,
        actualAmount: p.actualAmount,
        mustPay: p.mustPay,
        debt: p.debt,
        priority: p.priority || '',
      }));
  }, [costPlans, costCodes]);

  /* ── Expense lines ─────────────────────── */
  const expenseLines = useMemo((): PlanLine[] => {
    const expenseCodes = new Set(costCodes.filter(c => c.costType !== 'Income').map(c => c.code));
    return costPlans
      .filter(p => expenseCodes.has(p.costCode))
      .map(p => ({
        id: p.id,
        entityCode: p.costCode,
        entityName: p.costCodeName || p.costCode,
        entityGroup: p.groupName || 'Khác',
        plannedAmount: p.plannedAmount,
        actualAmount: p.actualAmount,
        mustPay: p.mustPay,
        debt: p.debt,
        priority: p.priority || '',
      }));
  }, [costPlans, costCodes]);

  /* ── Branch-grouped lines ──────────────── */
  const branchLines = useMemo((): PlanLine[] => {
    const branchMap = new Map<string, { planned: number; actual: number; mustPay: number; items: number }>();
    const sourceLines = activeTab === 'revenue' ? revenueLines : expenseLines;
    sourceLines.forEach(line => {
      const cp = costPlans.find(p => p.id === line.id);
      const branch = cp?.branchCode || 'Khác';
      const existing = branchMap.get(branch);
      if (existing) {
        existing.planned += line.plannedAmount;
        existing.actual += line.actualAmount;
        existing.mustPay += line.mustPay;
        existing.items += 1;
      } else {
        branchMap.set(branch, {
          planned: line.plannedAmount,
          actual: line.actualAmount,
          mustPay: line.mustPay,
          items: 1,
        });
      }
    });
    return Array.from(branchMap.entries()).map(([branch, data]) => ({
      id: `branch-${branch}`,
      entityCode: branch,
      entityName: branch,
      entityGroup: 'Chi nhánh',
      plannedAmount: data.planned,
      actualAmount: data.actual,
      mustPay: data.mustPay,
      debt: data.mustPay - data.planned,
      priority: '',
    }));
  }, [costPlans, activeTab, revenueLines, expenseLines]);

  /* ── Active server lines ───────────────── */
  const serverLines = useMemo((): PlanLine[] => {
    if (groupMode === 'branch') return branchLines;
    return activeTab === 'revenue' ? revenueLines : expenseLines;
  }, [groupMode, activeTab, branchLines, revenueLines, expenseLines]);

  /* ── Merged lines (server + local - deleted) ── */
  const activeLines = useMemo((): PlanLine[] => {
    const serverFiltered = serverLines.filter(l => !localDeletedIds.has(l.id));
    return [...serverFiltered, ...localAddedLines];
  }, [serverLines, localAddedLines, localDeletedIds]);

  /* ── Add / Copy / Remove handlers ───────── */
  const handleAddLine = useCallback(() => {
    localIdCounter.current += 1;
    const newId = `local-${localIdCounter.current}`;
    const newLine: PlanLine = {
      id: newId,
      entityCode: '',
      entityName: '',
      entityGroup: activeTab === 'revenue' ? 'Thu' : 'Chi',
      plannedAmount: 0,
      actualAmount: 0,
      mustPay: 0,
      debt: 0,
      priority: '',
    };
    setLocalAddedLines(prev => [...prev, newLine]);
    setEditedLines(prev => ({ ...prev, [newId]: 0 }));
    setEditedMustPay(prev => ({ ...prev, [newId]: 0 }));
    setEditedNotes(prev => ({ ...prev, [newId]: '' }));
    setSelectedLineIndex(activeLines.length);
  }, [activeTab, activeLines.length]);

  const handleCopyLine = useCallback(() => {
    if (selectedLineIndex < 0 || selectedLineIndex >= activeLines.length) return;
    const source = activeLines[selectedLineIndex];
    localIdCounter.current += 1;
    const newId = `local-${localIdCounter.current}`;
    const newLine: PlanLine = {
      ...source,
      id: newId,
    };
    setLocalAddedLines(prev => [...prev, newLine]);
    setEditedLines(prev => ({ ...prev, [newId]: source.plannedAmount }));
    setEditedMustPay(prev => ({ ...prev, [newId]: source.mustPay }));
    setEditedNotes(prev => ({ ...prev, [newId]: '' }));
    setSelectedLineIndex(activeLines.length);
  }, [selectedLineIndex, activeLines]);

  const handleRemoveLine = useCallback((lineId: string) => {
    if (lineId.startsWith('local-')) {
      setLocalAddedLines(prev => prev.filter(l => l.id !== lineId));
      setEditedLines(prev => { const next = { ...prev }; delete next[lineId]; return next; });
      setEditedMustPay(prev => { const next = { ...prev }; delete next[lineId]; return next; });
      setEditedNotes(prev => { const next = { ...prev }; delete next[lineId]; return next; });
    } else {
      setLocalDeletedIds(prev => { const next = new Set(prev); next.add(lineId); return next; });
    }
    setSelectedLineIndex(-1);
  }, []);

  /* ── Per-line field edit handlers ───────── */
  const handleCostCodeSelectForLine = useCallback((lineId: string, item: CostCodeDto) => {
    setLocalAddedLines(prev => prev.map(l =>
      l.id === lineId ? { ...l, entityCode: item.code, entityName: item.name, entityGroup: item.groupName || (activeTab === 'revenue' ? 'Thu' : 'Chi') } : l
    ));
  }, [activeTab]);

  /* ── Edit handlers ─────────────────────── */
  const handleEditStart = useCallback(() => {
    const init: Record<string, number> = {};
    const initMp: Record<string, number> = {};
    const initNote: Record<string, string> = {};
    activeLines.forEach(line => {
      init[line.id] = line.plannedAmount;
      initMp[line.id] = line.mustPay;
      initNote[line.id] = '';
    });
    setEditedLines(init);
    setEditedMustPay(initMp);
    setEditedNotes(initNote);
    setLocalAddedLines([]);
    setLocalDeletedIds(new Set());
    setEditMode(true);
  }, [activeLines]);

  const handleLineEdit = useCallback((id: string, value: number) => {
    setEditedLines(prev => ({ ...prev, [id]: value }));
  }, []);

  const handleMustPayEdit = useCallback((id: string, value: number) => {
    setEditedMustPay(prev => ({ ...prev, [id]: value }));
  }, []);

  const handleNoteEdit = useCallback((id: string, value: string) => {
    setEditedNotes(prev => ({ ...prev, [id]: value }));
  }, []);

  const handleCancel = useCallback(() => {
    setEditMode(false);
    setEditedLines({});
    setEditedMustPay({});
    setEditedNotes({});
    setLocalAddedLines([]);
    setLocalDeletedIds(new Set());
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      if (isCreate) {
        await fpcService.createPlanVoucher({
          voucherDate: localInputToISOWithOffset(voucherDate),
          planYear,
          planMonth,
          branchCode,
          description,
        });
      }

      const lines = activeLines
        .filter(l => (editedLines[l.id] ?? l.plannedAmount) > 0 || l.entityCode)
        .map(line => ({
          costCode: line.entityCode,
          plannedAmount: editedLines[line.id] ?? line.plannedAmount,
          mustPay: editedMustPay[line.id] ?? line.mustPay,
          note: editedNotes[line.id] ?? undefined,
        }));
      await fpcService.batchUpsertCostPlans({
        year: planYear,
        month: planMonth,
        branchCode: branchCode,
        lines,
      });
      dispatchAppToast(dispatch, { message: 'Đã lưu kế hoạch', type: 'success' });
      setEditMode(false);
      setEditedLines({});
      setEditedMustPay({});
      setEditedNotes({});
      setLocalAddedLines([]);
      setLocalDeletedIds(new Set());
      await fetchData(planYear, planMonth, branchCode);
      if (isCreate) {
        navigate('/tc/kh/ke-hoach');
      }
    } catch {
      dispatchAppToast(dispatch, { message: 'Lỗi khi lưu kế hoạch', type: 'error' });
    } finally {
      setSaving(false);
    }
  }, [dispatch, activeLines, editedLines, planYear, planMonth, branchCode, voucherDate, description, isCreate, fetchData, navigate]);

  /* ── Print ─────────────────────────────── */
  const handlePrint = useCallback(() => {
    const el = document.getElementById('plan-voucher-content');
    if (!el) return;
    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write([
      '<html><head><title>Phiếu kế hoạch</title><meta charset="utf-8"><style>',
      'body{font-family:Arial,sans-serif;padding:20px;color:#1e293b}',
      'table{width:100%;border-collapse:collapse;margin:16px 0;font-size:12px}',
      'th,td{padding:8px 12px;border:1px solid #e2e8f0;text-align:left}',
      'th{background:#f8fafc;font-weight:600;font-size:11px;text-transform:uppercase}',
      'h1{font-size:22px;color:#8b5cf6;margin:0 0 4px}',
      'h2{font-size:16px;color:#64748b;font-weight:400;margin:0 0 16px}',
      '.right{text-align:right}.money{font-family:monospace;text-align:right}',
      '.positive{color:#059669}.negative{color:#ef4444}',
      '.footer{display:flex;justify-content:flex-end;gap:24px;padding:12px;margin-top:12px}',
      '</style></head><body>',
      `<h1>Phiếu kế hoạch — ${activeTab === 'revenue' ? 'Kế hoạch thu' : 'Kế hoạch chi'} Tháng ${planMonth}/${planYear}</h1>`,
      `<h2>Ngày in: ${new Date().toLocaleString('vi-VN')}</h2>`,
      el.innerHTML,
      '</body></html>',
    ].join('\n'));
    win.document.close();
    win.print();
  }, [activeTab, planMonth, planYear]);

  /* ── Computed totals ───────────────────── */
  const serverGroupedLines = useMemo((): GroupTotal[] => {
    const map = new Map<string, PlanLine[]>();
    activeLines.forEach(line => {
      const g = line.entityGroup || 'Khác';
      if (!map.has(g)) map.set(g, []);
      map.get(g)!.push(line);
    });
    return Array.from(map.entries()).map(([group, items]) => ({
      group,
      items,
      totalPlanned: items.reduce((s, i) => s + i.plannedAmount, 0),
      totalActual: items.reduce((s, i) => s + i.actualAmount, 0),
      totalMustPay: items.reduce((s, i) => s + i.mustPay, 0),
      totalDebt: items.reduce((s, i) => s + i.debt, 0),
    }));
  }, [activeLines]);

  const totalPlanned = activeLines.reduce((s, l) => s + (editMode ? (editedLines[l.id] ?? l.plannedAmount) : l.plannedAmount), 0);
  const totalActual = activeLines.reduce((s, l) => s + l.actualAmount, 0);
  const totalVariance = totalActual - totalPlanned;
  const totalMustPay = activeLines.reduce((s, l) => s + l.mustPay, 0);
  const activeCount = activeLines.filter(l => (editMode ? (editedLines[l.id] ?? l.plannedAmount) : l.plannedAmount) > 0).length;

  const dateLabel = `Tháng ${planMonth}/${planYear}`;
  const periodMatch = loadedPeriod.year === planYear && loadedPeriod.month === planMonth;

  /* ── Render ────────────────────────────── */
  return (
    <div className={styles.page} data-form-page data-testid={`${TEST_ID}-page`}>
      {/* ── Toolbar (sticky top) ── */}
      <div className={styles.stickyTop}>
        <div className={styles.pageHeader}>
          <div className={styles.titleGroup}>
            <button className={styles.backBtn} onClick={() => navigate('/tc/kh/ke-hoach')} type="button">
              <i className="fas fa-arrow-left" />
            </button>
            <div className={styles.titleRow}>
              <h1 className={styles.title}>
                {isCreate ? 'Tạo phiếu kế hoạch' : (voucher ? `Phiếu ${voucher.code}` : 'Phiếu kế hoạch')}
              </h1>
            </div>
          </div>
          <FormActions align="end">
            {editMode ? (
              <>
                <Button onClick={handleCancel} data-testid={`${TEST_ID}-cancel-btn`}>
                  <i className="fas fa-times" /> Hủy
                </Button>
                <Button variant="primary" onClick={handleSave} disabled={saving} data-testid={`${TEST_ID}-save-btn`}>
                  <i className={`fas ${saving ? 'fa-spinner fa-spin' : 'fa-save'}`} />
                  {saving ? ' Đang lưu...' : ' Lưu'}
                </Button>
              </>
            ) : (
              <>
                <Button variant="primary" onClick={handleEditStart} data-testid={`${TEST_ID}-edit-btn`}>
                  <i className="fas fa-edit" /> Sửa
                </Button>
                <Button onClick={handlePrint} data-testid={`${TEST_ID}-print-btn`}>
                  <i className="fas fa-print" /> In
                </Button>
                <Button onClick={() => fetchData(planYear, planMonth, branchCode)} data-testid={`${TEST_ID}-refresh-btn`}>
                  <i className="fas fa-redo" /> Làm mới
                </Button>
              </>
            )}
          </FormActions>
        </div>
        {/* ── Mode hint (below toolbar) ── */}
        {!isCreate && !editMode && (
          <div className={styles.viewModeHint} data-testid={`${TEST_ID}-view-hint`}>
            <i className="fas fa-eye" /> Chế độ xem — nhấn <strong>Sửa</strong> để chỉnh sửa
          </div>
        )}
        {editMode && (
          <div className={styles.readOnlyHint} data-testid={`${TEST_ID}-edit-hint`}>
            <i className="fas fa-pen" /> Đang {isCreate ? 'tạo mới' : 'chỉnh sửa'} — Lưu hoặc Hủy
          </div>
        )}
      </div>

      {/* ── Scrollable content ── */}
      <div className={styles.pageFormScroll} id="plan-voucher-content">
        {/* ── Voucher loading ── */}
        {voucherLoading && (
          <FormSkeleton headerRows={2} lineRows={3} data-testid={`${TEST_ID}-form-skeleton`} />
        )}

        {!voucherLoading && <>
          {/* ── Header section with compact toggle ── */}
          <div
            className={styles.section}
            data-testid={`${TEST_ID}-section-header`}
          >
            <div className={styles.sectionTitleRow}>
              <h2 className={styles.sectionTitle}>Thông tin phiếu kế hoạch</h2>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span className={styles.sectionBadge}>{dateLabel}</span>
                <button
                  type="button"
                  className={styles.headerToggleBtn}
                  data-testid={`${TEST_ID}-header-${headerExpanded ? 'collapse' : 'expand'}`}
                  aria-expanded={headerExpanded}
                  onClick={() => setHeaderExpanded(v => !v)}
                >
                  <span className={styles.headerToggleIcon} aria-hidden>
                    <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
                  </span>
                  {headerExpanded ? 'Thu gọn' : 'Mở rộng'}
                </button>
              </div>
            </div>

            {/* Row 1: Số phiếu | Ngày lập | Kỳ kế hoạch | Chi nhánh */}
            <FormRowCol cols={4} data-testid={`${TEST_ID}-header-fields`}>
              <FormRowCol.Item label="Số phiếu" hidden={!headerExpanded}>
                <Input
                  value={voucherCode}
                  onChange={e => setVoucherCode(e.target.value)}
                  placeholder="PKH-YYYYMMDD-NNNN"
                  readOnly={!isCreate}
                  data-testid={`${TEST_ID}-voucherCode`}
                />
              </FormRowCol.Item>
              <FormRowCol.Item label="* Ngày lập">
                <Input
                  type="date"
                  value={voucherDate}
                  onChange={e => setVoucherDate(e.target.value)}
                  max={todayDateStr()}
                  data-testid={`${TEST_ID}-voucherDate`}
                />
              </FormRowCol.Item>
              <FormRowCol.Item label="* Kỳ kế hoạch">
                <div style={{ display: 'flex', gap: 8 }}>
                  <Select
                    value={planMonth}
                    onChange={(e: React.ChangeEvent<HTMLSelectElement>) => handlePeriodChange(planYear, parseInt(e.target.value))}
                    options={Array.from({ length: 12 }, (_, i) => ({ value: i + 1, label: `Tháng ${i + 1}` }))}
                    data-testid={`${TEST_ID}-planMonth`}
                    style={{ flex: 1 }}
                  />
                  <Input
                    type="number"
                    value={String(planYear)}
                    onChange={e => handlePeriodChange(parseInt(e.target.value) || now.getFullYear(), planMonth)}
                    style={{ width: 90 }}
                    data-testid={`${TEST_ID}-planYear`}
                  />
                </div>
              </FormRowCol.Item>
              <FormRowCol.Item label="Chi nhánh / Đơn vị">
                <SearchInput
                  config={companySearchConfig}
                  value={branchCode}
                  primaryDisplay={selectedCompany?.code}
                  secondaryDisplay={selectedCompany?.name}
                  onChange={(item) => handleBranchChange(item as ActiveCompanyItem)}
                  onClear={() => handleBranchChange(null)}
                  showLabel={false}
                  placeholder="Tất cả chi nhánh..."
                  data-testid={`${TEST_ID}-branch`}
                />
              </FormRowCol.Item>
            </FormRowCol>

            {/* Row 2: Diễn giải (full width — hidden when compact) */}
            {headerExpanded && (
              <FormRowCol cols={1} data-testid={`${TEST_ID}-header-desc`}>
                <FormRowCol.Item label="Diễn giải">
                  <Input
                    value={description}
                    onChange={e => setDescription(e.target.value)}
                    placeholder="Nhập mô tả kế hoạch"
                    data-testid={`${TEST_ID}-description`}
                  />
                </FormRowCol.Item>
              </FormRowCol>
            )}
          </div>

          {/* ── Loading ── */}
          {loading && (
            <FormSkeleton headerRows={1} lineRows={4} showFooter={false} data-testid={`${TEST_ID}-data-skeleton`} />
          )}

          {!loading && !periodMatch && (
            <div style={{ textAlign: 'center', padding: 32, color: '#94a3b8' }}>
              <i className="fas fa-sync" style={{ fontSize: 24, display: 'block', marginBottom: 8 }} />
              Đang tải kỳ {dateLabel}...
            </div>
          )}

          {!loading && periodMatch && (
            <>
              {/* ── Summary bar (view mode only) ── */}
              {!editMode && (
                <div className={styles.statsRow}>
                  <div className={styles.statCard}>
                    <span className={styles.statLabel}>Kỳ kế hoạch</span>
                    <span className={styles.statValue} style={{ fontSize: 18 }}>{dateLabel}</span>
                  </div>
                  <div className={styles.statCard}>
                    <span className={styles.statLabel}>Tổng kế hoạch</span>
                    <span className={styles.statValue}>{fCompact(totalPlanned)}</span>
                  </div>
                  <div className={styles.statCard}>
                    <span className={styles.statLabel}>Thực tế</span>
                    <span className={`${styles.statValue} ${totalActual >= 0 ? styles.positive : styles.negative}`}>{fCompact(totalActual)}</span>
                  </div>
                  <div className={styles.statCard}>
                    <span className={styles.statLabel}>Chênh lệch</span>
                    <span className={`${styles.statValue} ${totalVariance >= 0 ? styles.positive : styles.negative}`}>
                      {totalVariance >= 0 ? '+' : ''}{fCompact(totalVariance)}
                    </span>
                  </div>
                </div>
              )}

              {/* ── Tabs + Group toggle ── */}
              <div className={styles.section} style={{ padding: 0, overflow: 'hidden' }}>
                <div className={styles.tabBar}>
                  <button
                    className={`${styles.tabBtn} ${activeTab === 'revenue' ? styles.tabActiveRevenue : ''}`}
                    onClick={() => { setActiveTab('revenue'); setEditMode(false); setLocalAddedLines([]); setLocalDeletedIds(new Set()); }}
                    type="button"
                  >
                    <i className="fas fa-arrow-up" style={{ marginRight: 6 }} />
                    Kế hoạch thu
                  </button>
                  <button
                    className={`${styles.tabBtn} ${activeTab === 'expense' ? styles.tabActiveExpense : ''}`}
                    onClick={() => { setActiveTab('expense'); setEditMode(false); setLocalAddedLines([]); setLocalDeletedIds(new Set()); }}
                    type="button"
                  >
                    <i className="fas fa-arrow-down" style={{ marginRight: 6 }} />
                    Kế hoạch chi
                  </button>
                </div>

                <div style={{ padding: 20 }}>
                  {/* Group mode toggle */}
                  <div className={styles.sectionTitleRow}>
                    <h2 className={styles.sectionTitle}>
                      {activeTab === 'revenue' ? (
                        <><i className="fas fa-arrow-up" style={{ color: '#059669' }} /> Kế hoạch thu</>
                      ) : (
                        <><i className="fas fa-arrow-down" style={{ color: '#ef4444' }} /> Kế hoạch chi</>
                      )}
                      <span style={{ fontSize: 12, fontWeight: 400, color: '#94a3b8', marginLeft: 8 }}>
                        ({activeLines.length} dòng)
                      </span>
                    </h2>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                      {([['item', 'Theo khoản mục'], ['branch', 'Theo chi nhánh']] as [GroupMode, string][]).map(([mode, label]) => (
                        <button
                          key={mode}
                          onClick={() => { setGroupMode(mode); setEditMode(false); setLocalAddedLines([]); setLocalDeletedIds(new Set()); }}
                          className={groupMode === mode ? styles.groupBtnActive : styles.groupBtn}
                          type="button"
                        >{label}</button>
                      ))}
                    </div>
                  </div>

                  {/* Empty state */}
                  {activeLines.length === 0 && (
                    <div style={{ padding: '32px 0', textAlign: 'center', color: '#94a3b8' }}>
                      <i className="fas fa-inbox" style={{ fontSize: 32, display: 'block', marginBottom: 12 }} />
                      {branchCode
                        ? `Chưa có dữ liệu cho ${activeTab === 'revenue' ? 'kế hoạch thu' : 'kế hoạch chi'} kỳ ${dateLabel} tại chi nhánh đã chọn. `
                        : `Chưa có dữ liệu cho ${activeTab === 'revenue' ? 'kế hoạch thu' : 'kế hoạch chi'} kỳ ${dateLabel}. `}
                      Nhấn <strong>"Nhập số liệu"</strong> để khai báo.
                    </div>
                  )}

                  {activeLines.length > 0 && (
                    <>
                      {/* Lines table */}
                      <div className={styles.tableWrapper}>
                        <table className={styles.linesTable}>
                          <thead>
                            <tr>
                              <th style={{ width: 36 }}>STT</th>
                              <th style={{ width: 100 }}>Mã CP</th>
                              <th>
                                {activeTab === 'revenue' ? 'Khoản thu' : 'Khoản chi'}
                              </th>
                              {editMode ? (
                                <>
                                  <th className={styles.colRight} style={{ width: 160 }}>Kế hoạch</th>
                                  <th className={styles.colRight} style={{ width: 160 }}>Phải chi</th>
                                  <th style={{ width: 140 }}>Ghi chú</th>
                                  <th style={{ width: 40 }} />
                                </>
                              ) : (
                                <>
                                  <th className={styles.colRight} style={{ width: 140 }}>Kế hoạch</th>
                                  <th className={styles.colRight} style={{ width: 140 }}>Thực tế</th>
                                  <th className={styles.colRight} style={{ width: 100 }}>Chênh lệch</th>
                                  <th className={styles.colCenter} style={{ width: 100 }}>Trạng thái</th>
                                </>
                              )}
                            </tr>
                          </thead>
                          <tbody>
                            {serverGroupedLines.map(g => (
                              <React.Fragment key={g.group}>
                                <tr className={styles.groupRow}>
                                  <td colSpan={editMode ? 7 : 7} className={styles.groupCell}>
                                    {g.group}
                                    {!editMode && (
                                      <span className={styles.groupTotal}>
                                        {' '}— KH: {fCompact(g.totalPlanned)} / TT: {fCompact(g.totalActual)}
                                      </span>
                                    )}
                                  </td>
                                </tr>
                                {g.items.map((line, idx) => {
                                  const globalIdx = activeLines.findIndex(l => l.id === line.id);
                                  const isSelected = selectedLineIndex === globalIdx;
                                  const isLocal = line.id.startsWith('local-');
                                  const rowClass = [
                                    styles.lineRow,
                                    isSelected ? styles.lineRowSelected : '',
                                  ].filter(Boolean).join(' ');

                                  return (
                                    <tr
                                      key={line.id}
                                      className={rowClass}
                                      data-testid={`${TEST_ID}-line-${globalIdx}`}
                                      onClick={() => setSelectedLineIndex(globalIdx)}
                                    >
                                      <td style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 500 }}>{globalIdx + 1}</td>
                                      {/* Mã CP — SearchInput in edit mode for local lines, plain text for server lines */}
                                      <td style={{ fontWeight: 500, color: '#1e293b', fontSize: 12 }}>
                                        {editMode && isLocal ? (
                                          <SearchInput
                                            config={costCodeSearchConfig}
                                            value={line.entityCode}
                                            primaryDisplay={line.entityCode}
                                            secondaryDisplay={line.entityName}
                                            onChange={(item) => handleCostCodeSelectForLine(line.id, item as CostCodeDto)}
                                            onClear={() => {
                                              setLocalAddedLines(prev => prev.map(l =>
                                                l.id === line.id ? { ...l, entityCode: '', entityName: '' } : l
                                              ));
                                            }}
                                            showLabel={false}
                                            placeholder="Chọn mã CP..."
                                          />
                                        ) : (
                                          line.entityCode
                                        )}
                                      </td>
                                      {/* Tên khoản mục */}
                                      <td style={{ color: '#475569' }}>
                                        {editMode && isLocal ? (
                                          <span>{line.entityName || <span style={{ color: '#94a3b8' }}>—</span>}</span>
                                        ) : (
                                          <>
                                            {line.entityName}
                                            {!editMode && line.priority && (
                                              <span style={{
                                                marginLeft: 8,
                                                padding: '1px 6px',
                                                borderRadius: 4,
                                                fontSize: 10,
                                                fontWeight: 600,
                                                background: getPriorityBg(line.priority),
                                                color: getPriorityColor(line.priority),
                                              }}>
                                                {line.priority}
                                              </span>
                                            )}
                                          </>
                                        )}
                                      </td>
                                      {editMode ? (
                                        <>
                                          {/* Kế hoạch */}
                                          <td>
                                            <MoneyInput
                                              className={styles.lineInput}
                                              value={editedLines[line.id] ?? line.plannedAmount}
                                              onChange={v => handleLineEdit(line.id, v)}
                                            />
                                          </td>
                                          {/* Phải chi */}
                                          <td>
                                            <MoneyInput
                                              className={styles.lineInput}
                                              value={editedMustPay[line.id] ?? line.mustPay}
                                              onChange={v => handleMustPayEdit(line.id, v)}
                                            />
                                          </td>
                                          {/* Ghi chú */}
                                          <td>
                                            <Input
                                              className={`${styles.lineInput} ${styles.lineInputNote}`}
                                              value={editedNotes[line.id] ?? ''}
                                              onChange={e => handleNoteEdit(line.id, e.target.value)}
                                              placeholder="Nhập ghi chú..."
                                            />
                                          </td>
                                          {/* Xóa */}
                                          <td className={styles.tdDel}>
                                            <button
                                              type="button"
                                              className={styles.btnDeleteLine}
                                              onClick={e => { e.stopPropagation(); handleRemoveLine(line.id); }}
                                              title="Xóa dòng"
                                              data-testid={`${TEST_ID}-line-${globalIdx}-delete`}
                                            >
                                              <i className="fas fa-trash-alt" />
                                            </button>
                                          </td>
                                        </>
                                      ) : (
                                        <>
                                          <td className={styles.colAmount}>{fVnd(line.plannedAmount)}</td>
                                          <td className={styles.colAmount}>{fVnd(line.actualAmount)}</td>
                                          <td className={styles.colAmount}>
                                            {(() => {
                                              const diff = line.actualAmount - line.plannedAmount;
                                              return (
                                                <span style={{ fontWeight: 600, color: diff >= 0 ? '#059669' : '#ef4444' }}>
                                                  {diff >= 0 ? '+' : ''}{fVnd(diff)}
                                                </span>
                                              );
                                            })()}
                                          </td>
                                          <td className={styles.colCenter}>
                                            {(() => {
                                              const st = getStatusInfo(line.plannedAmount, line.actualAmount);
                                              return (
                                                <span className={styles.varianceBadge} style={{ background: st.bg, color: st.color }}>
                                                  {st.label}
                                                </span>
                                              );
                                            })()}
                                          </td>
                                        </>
                                      )}
                                    </tr>
                                  );
                                })}
                              </React.Fragment>
                            ))}
                          </tbody>
                          <tfoot>
                            <tr className={styles.footRow}>
                              <td colSpan={3} className={styles.footCell}>Tổng cộng</td>
                              {editMode ? (
                                <>
                                  <td className={styles.footAmount}>{fVnd(totalPlanned)}</td>
                                  <td className={styles.footAmount}>{fVnd(totalMustPay)}</td>
                                  <td /><td />
                                </>
                              ) : (
                                <>
                                  <td className={styles.footAmount}>{fVnd(totalPlanned)}</td>
                                  <td className={styles.footAmount}>{fVnd(totalActual)}</td>
                                  <td className={styles.footAmount} style={{ color: totalVariance >= 0 ? '#059669' : '#ef4444' }}>
                                    {totalVariance >= 0 ? '+' : ''}{fVnd(totalVariance)}
                                  </td>
                                  <td />
                                </>
                              )}
                            </tr>
                          </tfoot>
                        </table>
                      </div>

                      {/* Add / Copy row buttons (edit mode) */}
                      {editMode && (
                        <div className={styles.linesActions}>
                          <button
                            type="button"
                            className={styles.btnAddLine}
                            data-testid={`${TEST_ID}-add-line-btn`}
                            onClick={handleAddLine}
                          >
                            <i className="fas fa-plus" style={{ marginRight: 6 }} />
                            Thêm dòng
                          </button>
                          <button
                            type="button"
                            className={styles.btnCopyLine}
                            data-testid={`${TEST_ID}-copy-line-btn`}
                            onClick={handleCopyLine}
                            disabled={selectedLineIndex < 0}
                          >
                            <i className="fas fa-copy" style={{ marginRight: 6 }} />
                            Sao chép dòng
                          </button>
                        </div>
                      )}
                    </>
                  )}
                </div>
              </div>
            </>
          )}
        </>}
      </div>

      {/* ── Footer ── */}
      {!voucherLoading && activeCount > 0 && (
        <div className={styles.pageFormFooter}>
          <div className={styles.footer}>
            <div className={styles.footerLeft}>
              <span className={styles.footerTypeLabel} style={{
                color: activeTab === 'revenue' ? '#059669' : '#ef4444',
                fontWeight: 600,
                fontSize: 14,
                padding: '4px 10px',
                borderRadius: 4,
                background: activeTab === 'revenue' ? '#d1fae5' : '#fee2e2',
              }}>
                {activeTab === 'revenue' ? 'Kế hoạch thu' : 'Kế hoạch chi'}
              </span>
              <span style={{ fontSize: 13, color: '#64748b' }}>
                {editMode ? `Đang chỉnh sửa · ${activeCount} dòng` : `${activeCount} dòng`}
              </span>
            </div>
            <div className={styles.totalBlock}>
              {!editMode && (
                <LabelMoney
                  label="Thực tế:"
                  value={totalActual}
                  variant="footer"
                  data-testid={`${TEST_ID}-footer-totalActual`}
                />
              )}
              <LabelMoney
                label="Tổng kế hoạch:"
                value={totalPlanned}
                variant="footer"
                emphasize
                data-testid={`${TEST_ID}-footer-totalPlanned`}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PlanVoucherPage;
